from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    # Look for jira_state.json in external_services_path first, then workspace
    jira_path = None
    if external_services_path:
        candidate = Path(external_services_path) / 'jira_state.json'
        if candidate.exists():
            jira_path = candidate
    if jira_path is None:
        candidate = Path(workspace_path) / 'jira_state.json'
        if candidate.exists():
            jira_path = candidate
    if jira_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'jira_state.json not found in workspace or external_services_path'}

    try:
        with open(jira_path) as f:
            jira_data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading jira_state.json: {e}'}

    target_ids = ['OPS-2', 'OPS-3', 'OPS-7', 'OPS-8']

    # The rubric says: "the top-level comments object contains comment lists keyed by issue ID"
    # So we expect jira_data to have a top-level key "comments" which is a dict keyed by issue ID
    # e.g. { "comments": { "OPS-2": [...], "OPS-3": [...], ... }, ... }

    # Try to find the comments object
    comments_obj = None
    if isinstance(jira_data, dict):
        # Direct top-level "comments" key
        if 'comments' in jira_data:
            comments_obj = jira_data['comments']
        # Maybe nested under another key
        if comments_obj is None:
            for k, v in jira_data.items():
                if isinstance(v, dict) and any(tid in v or tid.lower() in str(v).lower() for tid in target_ids):
                    # Check if this looks like a comments-by-issue-id dict
                    if any(isinstance(vv, list) for vv in v.values()):
                        comments_obj = v
                        break

    # Fallback: search the entire structure for comment lists
    if comments_obj is None:
        # Try to find any dict that has issue IDs as keys mapping to lists
        def find_comments_dict(obj, depth=0):
            if depth > 5:
                return None
            if isinstance(obj, dict):
                # Check if this dict itself has target IDs as keys mapping to lists
                matching = sum(1 for tid in target_ids if tid in obj and isinstance(obj.get(tid), list))
                if matching >= 1:
                    return obj
                for k, v in obj.items():
                    result = find_comments_dict(v, depth + 1)
                    if result is not None:
                        return result
            return None
        comments_obj = find_comments_dict(jira_data)

    if comments_obj is None or not isinstance(comments_obj, dict):
        return {'pass': False, 'score': 0.0, 'feedback': f'No top-level comments object found in jira_state.json. Top-level keys: {list(jira_data.keys()) if isinstance(jira_data, dict) else "not a dict"}'}

    failures = []
    successes = []

    for tid in target_ids:
        tid_lower = tid.lower()

        # Find the comment list for this issue ID (case-insensitive key match)
        comment_list = None
        for key, val in comments_obj.items():
            if key.lower() == tid_lower or key.upper() == tid.upper():
                comment_list = val
                break

        if comment_list is None:
            # Also try looking inside issues structure for comments
            failures.append(f'{tid}: no comment list found keyed by this issue ID in the comments object')
            continue

        if not isinstance(comment_list, list):
            comment_list = [comment_list]

        # Check each comment for required content:
        # 1. transaction ID (the SUSP-XXX)
        # 2. target GL code (some numeric code or GL reference)
        # 3. phrase "FIN-100 Cleared & Posted" (case-insensitive)
        found_valid_comment = False
        best_comment_info = ''
        for comment in comment_list:
            comment_text = _get_comment_text(comment)
            comment_lower = comment_text.lower()

            # Check for transaction ID
            has_tid = tid_lower in comment_lower

            # Check for "FIN-100 Cleared & Posted" (case-insensitive, flexible on & vs and)
            has_fin100_cleared_posted = bool(
                re.search(r'fin[\-\s]?100\s+cleared\s*[&and]+\s*posted', comment_lower)
            )
            # More lenient: just check for fin-100 and cleared and posted separately
            if not has_fin100_cleared_posted:
                has_fin100 = bool(re.search(r'fin[\-\s]?100', comment_lower))
                has_cleared = 'cleared' in comment_lower
                has_posted = 'posted' in comment_lower
                has_fin100_cleared_posted = has_fin100 and has_cleared and has_posted

            # Check for GL code - look for numeric codes (4+ digits) or GL/account references
            has_gl = bool(re.search(r'\d{4,}', comment_text)) or bool(re.search(r'(gl|account|acct|ledger)', comment_lower))

            if has_tid and has_fin100_cleared_posted and has_gl:
                found_valid_comment = True
                break

            # Track what we found for feedback
            if has_tid or has_fin100_cleared_posted:
                parts = []
                if has_tid: parts.append('has TID')
                if has_fin100_cleared_posted: parts.append('has FIN-100 Cleared & Posted')
                if has_gl: parts.append('has GL code')
                best_comment_info = f' (best match: {", ".join(parts)}, text preview: {comment_text[:200]})'

        if found_valid_comment:
            successes.append(tid)
        else:
            num_comments = len(comment_list)
            failures.append(f'{tid}: no comment (out of {num_comments}) found containing transaction ID, GL code, and "FIN-100 Cleared & Posted"{best_comment_info}')

    score = len(successes) / len(target_ids)

    if failures:
        return {
            'pass': False,
            'score': score,
            'feedback': f'Passed: {successes}. Failures: ' + '; '.join(failures)
        }

    return {
        'pass': True,
        'score': 1.0,
        'feedback': f'All cleared items ({", ".join(target_ids)}) have Jira comments with transaction ID, GL code, and FIN-100 Cleared & Posted'
    }


def _get_comment_text(comment):
    """Extract text content from a comment object."""
    if isinstance(comment, str):
        return comment
    if isinstance(comment, dict):
        parts = []
        for key in ('body', 'text', 'content', 'message', 'description', 'note', 'comment'):
            if key in comment:
                val = comment[key]
                if isinstance(val, str):
                    parts.append(val)
                elif isinstance(val, list):
                    parts.append(json.dumps(val))
                elif isinstance(val, dict):
                    parts.append(json.dumps(val))
        if not parts:
            return json.dumps(comment)
        return ' '.join(parts)
    return str(comment)

from pathlib import Path
