def extract_adf_text(node):
    """Recursively extract text from Atlassian Document Format nodes."""
    texts = []
    if isinstance(node, dict):
        if 'text' in node:
            texts.append(str(node['text']))
        for key in ('content', 'body'):
            if key in node:
                val = node[key]
                if isinstance(val, list):
                    for item in val:
                        texts.extend(extract_adf_text(item))
                elif isinstance(val, dict):
                    texts.extend(extract_adf_text(val))
    elif isinstance(node, list):
        for item in node:
            texts.extend(extract_adf_text(item))
    return texts

