    fin_exception_tickets = {}

    if isinstance(issues, dict):
        for key, val in issues.items():
            key_upper = key.upper()
            if key_upper.startswith('FIN-') and 'BOARD' not in key_upper:
                fin_exception_tickets[key] = val
    elif isinstance(issues, list):
        # If issues is a list, look for key/id fields
        for item in issues:
            if isinstance(item, dict):
                key = str(item.get('key', '') or item.get('id', '') or '')
                key_upper = key.upper()
                if key_upper.startswith('FIN-') and 'BOARD' not in key_upper:
                    fin_exception_tickets[key] = item
    else:
        return {'pass': False, 'score': 0.0, 'feedback': f'issues object is of unexpected type: {type(issues)}'}

    # Check count
    num_tickets = len(fin_exception_tickets)
    failures = []
