def _flatten_issues(jira_data):
    """Extract all individual issue dicts from the jira_state structure."""
    all_issues = []
    if not isinstance(jira_data, dict):
        if isinstance(jira_data, list):
            return [i for i in jira_data if isinstance(i, dict)]
        return []

    for key, val in jira_data.items():
        if key == 'comments':
            continue
        if isinstance(val, list):
            for item in val:
                if isinstance(item, dict):
                    all_issues.append(item)
        elif isinstance(val, dict):
            if any(k in val for k in ('key', 'fields', 'id', 'assignee', 'summary')):
                all_issues.append(val)
            else:
                for sub_key, sub_val in val.items():
                    if isinstance(sub_val, dict):
                        all_issues.append(sub_val)
    return all_issues


def _check_assignee_for_jennifer(ticket):
    """Check ONLY the assignee field of a ticket for jennifer.walsh."""
    jennifer_variants = ['jennifer.walsh', 'jennifer walsh', 'jennifer_walsh', 'jwalsh', 'j.walsh']

    if not isinstance(ticket, dict):
        return False

    containers = [ticket]
    if isinstance(ticket.get('fields'), dict):
        containers.append(ticket['fields'])

    for container in containers:
        for field_name in ['assignee', 'assigned_to', 'owner']:
            val = container.get(field_name)
            if val is None:
                continue
            if isinstance(val, str):
                if any(v in val.lower() for v in jennifer_variants):
                    return True
            elif isinstance(val, dict):
                for subfield in ['accountId', 'displayName', 'emailAddress', 'name', 'key']:
                    subval = val.get(subfield, '')
                    if subval and isinstance(subval, str):
                        if any(v in subval.lower() for v in jennifer_variants):
                            return True
    return False


def _get_assignee_display(ticket):
    """Extract a human-readable assignee string for error messages."""
    if not isinstance(ticket, dict):
        return 'unknown'
    for container in [ticket.get('fields', {}), ticket]:
        if not isinstance(container, dict):
            continue
        for field_name in ['assignee', 'assigned_to', 'owner']:
            val = container.get(field_name)
            if val is None:
                continue
            if isinstance(val, dict):
                return val.get('displayName', val.get('accountId', str(val)))
            if isinstance(val, str) and val:
                return val
    return 'unknown'


def _get_issue_key(issue):
