    if not isinstance(issue, dict):
        return ''
    key = issue.get('key')
    if isinstance(key, str):
        return key
    fields = issue.get('fields')
    if isinstance(fields, dict):
        k = fields.get('key')
        if isinstance(k, str):
            return k
    return ''


def _get_project_key(issue):
