    if not isinstance(issue, dict):
        return ''
    fields = issue.get('fields') if isinstance(issue.get('fields'), dict) else {}
    proj = fields.get('project') if isinstance(fields, dict) else None
    if isinstance(proj, dict):
        pk = proj.get('key')
        if isinstance(pk, str):
            return pk
    return ''


def _summary_and_description_text(issue):
    """Return summary + description text for matching SUSP-IDs against, lowercased."""
    if not isinstance(issue, dict):
        return ''
    fields = issue.get('fields') if isinstance(issue.get('fields'), dict) else issue
    parts = []
    summary = fields.get('summary')
    if isinstance(summary, str):
        parts.append(summary)
    desc = fields.get('description')
    if isinstance(desc, str):
        parts.append(desc)
    elif isinstance(desc, dict):
        # Atlassian Document Format — just dump it; SUSP-XXX will appear as a substring
        parts.append(json.dumps(desc))
    return ' '.join(parts)


