        candidate = Path(workspace_path) / 'jira_state.json'
        if candidate.exists():
            jira_path = candidate
    if jira_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'jira_state.json not found'}

    try:
        with open(jira_path) as f:
            jira_data = json.load(f)

        all_issues = _flatten_issues(jira_data)

        # Restrict to FIN-N tickets only (these are the exception tickets the agent creates).
        # Exclude SUSP-* sub-tasks regardless of their labels.
        fin_tickets = []
        for issue in all_issues:
            ikey = _get_issue_key(issue)
            pkey = _get_project_key(issue)
            if ikey.startswith('FIN-') or pkey == 'FIN':
                # Make sure we don't accidentally include something like 'FIN-Exceptions'
                # as a key — real keys look like FIN-<number>.
                tail = ikey.split('-', 1)[1] if '-' in ikey else ''
                if tail.isdigit() or pkey == 'FIN':
                    fin_tickets.append(issue)

        required_ids = ['OPS-4', 'OPS-5', 'OPS-6', 'OPS-9',
                        'OPS-10', 'OPS-11', 'OPS-12']
        failures = []
        found_tickets = []

        for rid in required_ids:
            rid_lower = rid.lower()
            # Find FIN tickets whose summary/description references this SUSP id
            matching = [t for t in fin_tickets
                        if rid_lower in _summary_and_description_text(t).lower()]

            if not matching:
                failures.append(f'{rid}: no FIN-* exception ticket found referencing this ID')
                continue

            # If multiple FIN tickets reference the same SUSP id, require that at least one
            # is assigned to jennifer.walsh. (Adjust to "all" if the criterion demands it.)
            ok_ticket = next((t for t in matching if _check_assignee_for_jennifer(t)), None)

            if ok_ticket is not None:
                found_tickets.append(rid)
            else:
                # Report the first matching ticket's assignee for context
                t = matching[0]
                assignee_info = _get_assignee_display(t)
                tkey = _get_issue_key(t) or '(unknown key)'
                failures.append(f'{rid}: FIN ticket {tkey} assignee is "{assignee_info}", not jennifer.walsh')

        if failures:
            score = len(found_tickets) / len(required_ids)
            return {
                'pass': False,
                'score': score,
                'feedback': (f'Found {len(found_tickets)}/{len(required_ids)} correctly assigned. '
                             f'Failures: ' + '; '.join(failures))
            }

        return {
            'pass': True,
            'score': 1.0,
            'feedback': (f"All {len(required_ids)} FIN-Exception tickets "
                         f"({', '.join(required_ids)}) are assigned to jennifer.walsh")
        }
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error processing jira_state.json: {e}'}

from pathlib import Path
import json

def _extract_adf_text(node):
    """Recursively extract text from Atlassian Document Format nodes."""
    texts = []
    if isinstance(node, dict):
        if 'text' in node:
            texts.append(str(node['text']))
        for key in ('body', 'content', 'children'):
            child = node.get(key)
            if isinstance(child, list):
                for item in child:
                    texts.extend(_extract_adf_text(item))
            elif isinstance(child, dict):
                texts.extend(_extract_adf_text(child))
    elif isinstance(node, list):
        for item in node:
            texts.extend(_extract_adf_text(item))
    return texts

def verify(workspace_path, external_services_path=None):
    # Locate jira_state.json
    jira_path = None
    if external_services_path:
        candidate = Path(external_services_path) / 'jira_state.json'
        if candidate.exists():
            jira_path = candidate
    if jira_path is None:
        candidate = Path(workspace_path) / 'jira_state.json'
        if candidate.exists():
            jira_path = candidate
    if jira_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'jira_state.json not found in external_services_path or workspace_path'}

    try:
        with open(jira_path) as f:
            jira_data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading jira_state.json: {e}'}

    if not isinstance(jira_data, dict):
        return {'pass': False, 'score': 0.0, 'feedback': 'jira_state.json top-level is not a dict'}

    # The rubric says: "the top-level comments object contains comment lists keyed by issue ID"
    comments_obj = jira_data.get('comments', {})
    if not isinstance(comments_obj, dict):
        # Fallback: maybe the entire jira_data acts as a container; try to find comments elsewhere
        comments_obj = {}

    # Also collect all issues from other top-level keys (issues list, etc.) for fallback
    all_issues = []
    for key, val in jira_data.items():
        if key == 'comments':
            continue
        if isinstance(val, list):
            all_issues.extend(val)
        elif isinstance(val, dict):
            all_issues.append(val)

    required_ids = ['OPS-4', 'OPS-5', 'OPS-9', 'OPS-11', 'OPS-12']
    escalation_keywords = ['escalat', 'exception', 'missing', 'conflict', 'approval', 'pdf', 'slack', 'self', 'manager']

    failures = []
    successes = []

    for tid in required_ids:
        combined_text = ''

        # Primary path: top-level comments object keyed by issue ID
        comment_list = comments_obj.get(tid, [])
        if not isinstance(comment_list, list):
            comment_list = [comment_list] if comment_list else []

        for comment in comment_list:
            # Extract text via ADF walking
            adf_texts = _extract_adf_text(comment)
            combined_text += ' '.join(adf_texts) + ' '
            # Also grab any plain string fields
            if isinstance(comment, dict):
                for field in ('body', 'text', 'content'):
                    v = comment.get(field)
                    if isinstance(v, str):
                        combined_text += v + ' '
            elif isinstance(comment, str):
                combined_text += comment + ' '

        # Fallback: look through issues for matching issue and its comments
        if not combined_text.strip():
            for issue in all_issues:
                if not isinstance(issue, dict):
                    continue
                issue_str = json.dumps(issue)
                if tid in issue_str:
                    # Try to get comments from the issue object
                    issue_comments = issue.get('comments', issue.get('comment', []))
                    if not isinstance(issue_comments, list):
                        issue_comments = [issue_comments] if issue_comments else []
                    for comment in issue_comments:
                        adf_texts = _extract_adf_text(comment)
                        combined_text += ' '.join(adf_texts) + ' '
                        if isinstance(comment, dict):
                            for field in ('body', 'text', 'content'):
                                v = comment.get(field)
                                if isinstance(v, str):
                                    combined_text += v + ' '
                        elif isinstance(comment, str):
                            combined_text += comment + ' '
                    # Also check description/notes as last resort
                    if not combined_text.strip():
                        desc = str(issue.get('description', '') or '') + ' ' + str(issue.get('notes', '') or '')
                        combined_text += desc
                    break

        combined_lower = combined_text.lower().strip()

        if not combined_lower:
            failures.append(f'{tid}: no comments found in jira_state.json comments object or issue data')
            continue

        has_escalation = any(kw in combined_lower for kw in escalation_keywords)
        if has_escalation:
            matched = [kw for kw in escalation_keywords if kw in combined_lower]
            # For OPS-12 specifically, require a negative indicator to distinguish
            # escalation comments ("approval insufficient") from clearing comments
            # ("approval found"). This prevents false positives when models clear
            # OPS-12 instead of excepting it.
            if tid == 'OPS-12':
                negative_indicators = ['missing', 'insufficient', 'invalid', 'not a manager', 'not manager', 'escalat', 'exception', 'unauthorized', 'junior', 'self-approv', 'improper', 'flag', 'issue', 'concern', 'problem', 'must be']
                has_negative = any(neg in combined_lower for neg in negative_indicators)
                if not has_negative:
                    failures.append(f'{tid}: comment mentions escalation keywords {matched} but lacks a negative indicator — may be a clearing comment, not an escalation')
                else:
                    successes.append(f'{tid}: found escalation keywords {matched} with negative indicator')
            else:
                successes.append(f'{tid}: found escalation keywords {matched}')
        else:
            failures.append(f'{tid}: comment text found but no escalation keyword detected. Text snippet: "{combined_lower[:300]}"')

    score = len(successes) / len(required_ids)

    if failures:
        feedback = 'Failures: ' + '; '.join(failures)
        if successes:
            feedback += ' | Successes: ' + '; '.join(successes)
        return {'pass': False, 'score': score, 'feedback': feedback}

    return {'pass': True, 'score': 1.0, 'feedback': 'All required subtasks (OPS-4, OPS-5, OPS-9, OPS-11, OPS-12) have comments noting escalation reasons. Details: ' + '; '.join(successes)}
